    scalar_t warp_max = warp_reduce_max(thread_max);

    // First thread in each warp writes to shared memory
    __shared__ scalar_t warp_maxs[32];
    if (lane_id == 0) {
        warp_maxs[warp_id] = warp_max;
    }
    __syncthreads();

    // Final reduction across warps
    if (warp_id == 0) {
        scalar_t val = (lane_id < (blockDim.x + 31) / 32) ? warp_maxs[lane_id] : -1e10f;
        scalar_t block_max = warp_reduce_max(val);

        if (tid == 0) {
            int out_idx = batch_idx * dim1 + dim1_idx;
            output[out_idx] = block_max;
